module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);
    // TODO: Please implement according to the description.
    // Note: it is recommended to use "always" and "if" statements.
    reg [3:0] cnt;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'd0;
            dout_valid <= 1'b0;
        end
        else if (din_valid) begin
            if (cnt == 4'd7) begin
                dout_valid <= 1'b1;
                cnt <= 4'd0;
            end
            else begin
                dout_valid <= 1'b0;
                cnt <= cnt + 1;
            end
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) dout_parallel <= 8'd0;
        else if (din_valid) begin
            dout_parallel <= {dout_parallel[6:0], din_serial};
        end
    end
endmodule
